20	#[repr(C)]
21	#[cfg_attr(
22	    any(
23	        // List of target_arch that can have 128-bit atomics: https://github.com/taiki-e/portable-atomic/blob/HEAD/src/imp/atomic128/README.md
24	        target_arch = "x86_64",
25	        target_arch = "aarch64",
26	        target_arch = "arm64ec",
