38	#[test]
39	fn is_lock_free() {
40	    assert_eq!(
41	        core::mem::size_of::<Instant>(),
42	        core::mem::size_of::<Align<Instant>>()
43	    );
44	    if cfg!(any(
45	        all(target_arch = "x86_64", target_vendor = "apple"),
46	        target_arch = "aarch64",
47	    )) || rustversion::cfg!(since(1.78)) && cfg!(all(target_arch = "x86_64", windows))
48	        || rustversion::cfg!(since(1.84))
49	            && cfg!(any(target_arch = "arm64ec", target_arch = "s390x"))
50	        || rustversion::cfg!(since(1.95))
51	            && cfg!(all(target_arch = "powerpc64", target_endian = "little"))
52	    {
53	        assert_eq!(
54	            AtomicCell::<Align<Instant>>::is_lock_free(),
55	            cfg!(not(any(miri, crossbeam_loom, crossbeam_sanitize)))
56	        );
57	    }
