164	    #[inline]
165	    fn try_select(&self, token: &mut Token) -> bool {
166	        match self.try_recv() {
167	            Ok(msg) => {
168	                token.tick = Some(msg);
169	                true
170	            }
171	            Err(TryRecvError::Disconnected) => {
172	                token.tick = None;
173	                true
174	            }
175	            Err(TryRecvError::Empty) => false,
176	        }
177	    }
178	
179	    #[inline]
180	    fn deadline(&self) -> Option<Instant> {
181	        Some(self.delivery_time.load().0)
182	    }
183	
184	    #[inline]
185	    fn register(&self, _oper: Operation, _cx: &Context) -> bool {
186	        self.is_ready()
187	    }
188	
189	    #[inline]
190	    fn unregister(&self, _oper: Operation) {}
191	
192	    #[inline]
193	    fn accept(&self, token: &mut Token, _cx: &Context) -> bool {
194	        self.try_select(token)
195	    }
196	
197	    #[inline]
198	    fn is_ready(&self) -> bool {
199	        !self.is_empty()
200	    }
201	
202	    #[inline]
203	    fn watch(&self, _oper: Operation, _cx: &Context) -> bool {
204	        self.is_ready()
205	    }
206	
207	    #[inline]
208	    fn unwatch(&self, _oper: Operation) {}
209	}
